import{c as n,S as i,j as h,m as a}from"./chunks/framework.8aa1YH_s.js";const u=JSON.parse('{"title":"Hướng dẫn cho Giáo viên","description":"","frontmatter":{},"headers":[],"relativePath":"giao-vien/index.md","filePath":"giao-vien/index.md","lastUpdated":0}'),o={name:"giao-vien/index.md"};function d(e,t,c,r,l,s){return i(),h("div",null,[...t[0]||(t[0]=[a('<h1 id="huong-dan-cho-giao-vien" tabindex="-1">Hướng dẫn cho Giáo viên <a class="header-anchor" href="#huong-dan-cho-giao-vien" aria-label="Permalink to “Hướng dẫn cho Giáo viên”">​</a></h1><p>Khu vực Giáo viên (<code>https://lamsonedutech.vn/teacher/...</code>) là không gian làm việc dành cho giáo viên: tạo khóa học, soạn bài giảng, ra đề thi, quản lý lớp học và chấm điểm.</p><h2 id="so-đo-menu-giao-vien" tabindex="-1">Sơ đồ menu Giáo viên <a class="header-anchor" href="#so-đo-menu-giao-vien" aria-label="Permalink to “Sơ đồ menu Giáo viên”">​</a></h2><p>Sau khi đăng nhập tại <code>https://lamsonedutech.vn/auth/giaovien</code>, bạn sẽ thấy menu bên trái:</p><table tabindex="0"><thead><tr><th>Mục</th><th>Đường dẫn</th><th>Mô tả</th></tr></thead><tbody><tr><td><strong>Tổng quan</strong></td><td><code>https://lamsonedutech.vn/teacher/dashboard</code></td><td>Số liệu nhanh: số khóa, học viên, đề thi</td></tr><tr><td><strong>Quản lý khóa học</strong></td><td><code>https://lamsonedutech.vn/teacher/course-management</code></td><td>Tạo &amp; quản lý khóa do bạn phụ trách</td></tr><tr><td><strong>Quản lý lớp học</strong></td><td><code>https://lamsonedutech.vn/teacher/class-management/:courseId</code></td><td>Quản lý từng lớp (vào từ chi tiết khóa)</td></tr><tr><td><strong>Quản lý điểm thi</strong></td><td><code>https://lamsonedutech.vn/teacher/score-exam</code></td><td>Xem &amp; xuất điểm của học viên</td></tr><tr><td><strong>Quản lý tiêu chí</strong></td><td><code>https://lamsonedutech.vn/teacher/criteria</code></td><td>Tạo tiêu chí ra đề ngẫu nhiên</td></tr><tr><td><strong>Hỏi đáp</strong></td><td><code>https://lamsonedutech.vn/teacher/reply</code></td><td>Trả lời câu hỏi của học viên</td></tr><tr><td><strong>Tài khoản cá nhân</strong></td><td><code>https://lamsonedutech.vn/teacher/profile</code></td><td>Sửa hồ sơ, đổi mật khẩu</td></tr></tbody></table><h2 id="mot-ngay-lam-viec-đien-hinh" tabindex="-1">Một ngày làm việc điển hình <a class="header-anchor" href="#mot-ngay-lam-viec-đien-hinh" aria-label="Permalink to “Một ngày làm việc điển hình”">​</a></h2><ol><li><p><strong>Sáng sớm</strong>:</p><ul><li>Mở Dashboard, kiểm tra học viên mới đăng ký lớp / khóa.</li><li>Vào Hỏi đáp, trả lời các câu hỏi qua đêm.</li></ul></li><li><p><strong>Trong ngày</strong>:</p><ul><li>Cập nhật bài giảng / chỉnh đề thi nếu có nội dung mới.</li><li>Theo dõi tiến độ học của các lớp.</li></ul></li><li><p><strong>Cuối tuần</strong>:</p><ul><li>Xuất điểm thi → gửi phụ huynh / báo cáo.</li><li>Tổng kết các vấn đề học viên hay mắc → ghi note cho khóa sau.</li></ul></li></ol><h2 id="quy-trinh-tao-mot-khoa-hoc-moi" tabindex="-1">Quy trình tạo một khóa học mới <a class="header-anchor" href="#quy-trinh-tao-mot-khoa-hoc-moi" aria-label="Permalink to “Quy trình tạo một khóa học mới”">​</a></h2><p>Nếu bạn được giao tạo một khóa từ đầu, theo trình tự:</p><ol><li><strong>Tạo khóa</strong>: <a href="./quan-ly-khoa-hoc">Quản lý khóa học</a>.</li><li><strong>Tạo cây nội dung</strong>: chương → chuyên đề → bài giảng tại <a href="./soan-bai-giang">Soạn bài giảng</a>.</li><li><strong>Tạo tiêu chí đề thi</strong> (nếu dùng đề ngẫu nhiên) tại <a href="./quan-ly-tieu-chi">Tiêu chí đề thi</a>.</li><li><strong>Tạo đề kiểm tra cuối chuyên đề</strong> + <strong>đề ôn khóa học</strong>.</li><li>(Tùy chọn) Tạo lớp học và mời học viên vào: <a href="./quan-ly-lop-hoc">Quản lý lớp học</a>.</li><li>Khi khóa hoàn thiện, báo Admin <strong>Công khai</strong> để học viên thấy.</li></ol><h2 id="khac-biet-vai-tro-giao-vien-vs-admin" tabindex="-1">Khác biệt vai trò Giáo viên vs Admin <a class="header-anchor" href="#khac-biet-vai-tro-giao-vien-vs-admin" aria-label="Permalink to “Khác biệt vai trò Giáo viên vs Admin”">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Giáo viên</th><th>Admin</th></tr></thead><tbody><tr><td>Tạo / sửa khóa của mình</td><td>✅</td><td>✅ (toàn bộ)</td></tr><tr><td>Tạo / sửa khóa của giáo viên khác</td><td>❌</td><td>✅</td></tr><tr><td>Xem điểm học viên trong khóa mình</td><td>✅</td><td>✅</td></tr><tr><td>Xem điểm học viên ngoài khóa mình</td><td>❌</td><td>✅</td></tr><tr><td>Quản lý tài khoản học viên (sửa/khóa/xóa)</td><td>❌</td><td>✅</td></tr><tr><td>Quản lý hóa đơn</td><td>❌</td><td>✅</td></tr><tr><td>Phát mã giảm giá</td><td>❌</td><td>✅</td></tr></tbody></table><h2 id="luu-y-đau-tien-cho-giao-vien-moi" tabindex="-1">Lưu ý đầu tiên cho giáo viên mới <a class="header-anchor" href="#luu-y-đau-tien-cho-giao-vien-moi" aria-label="Permalink to “Lưu ý đầu tiên cho giáo viên mới”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Đổi mật khẩu lần đầu</p><p>Tài khoản giáo viên do Admin cấp. <strong>Vào ngay <a href="./ho-so-ca-nhan">Tài khoản cá nhân</a> đổi mật khẩu</strong> sau lần đăng nhập đầu tiên.</p></div><div class="tip custom-block"><p class="custom-block-title">Hoàn thiện hồ sơ trước khi dạy</p><p>Ảnh đại diện, giới thiệu ngắn, bằng cấp hiển thị <strong>công khai</strong> ở trang khóa học. Học viên sẽ tin tưởng và đăng ký nhiều hơn khi hồ sơ chuẩn.</p></div><div class="warning custom-block"><p class="custom-block-title">Khi gặp lỗi quyền</p><p>Một số mục có thể không hiển thị nếu Admin chưa cấp đủ quyền. Liên hệ Admin để được hỗ trợ.</p></div><h2 id="tiep-theo" tabindex="-1">Tiếp theo <a class="header-anchor" href="#tiep-theo" aria-label="Permalink to “Tiếp theo”">​</a></h2><p>→ Bắt đầu với <a href="./dashboard">Dashboard</a> hoặc đi thẳng đến <a href="./quan-ly-khoa-hoc">Quản lý khóa học</a>.</p>',18)])])}const m=n(o,[["render",d]]);export{u as __pageData,m as default};
